// MARK: - Crypto Utilities

class CryptoUtils {
    static func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes)
    }
    
    static func derivePublicKey(from privateKey: Data) -> Data {
        let key = privateKey.withUnsafeBytes { ptr -> [UInt8] in
            return Array(ptr)
        }
        
        var publicKey = secp256k1_pubkey()
        var ctx = secp256k1_context_create(UInt32(SECP256K1_CONTEXT_SIGN | SECP256K1_CONTEXT_VERIFY))
        defer { secp256k1_context_destroy(ctx) }
        
        _ = secp256k1_ec_pubkey_create(ctx, &publicKey, key)
        
        var outputLen = 65
        var output = [UInt8](repeating: 0, count: outputLen)
        secp256k1_ec_pubkey_serialize(ctx, &output, &outputLen, &publicKey, UInt32(SECP256K1_EC_UNCOMPRESSED))
        
        return Data(output)
    }
    
    static func sha256(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func ripemd160(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_RIPEMD160_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_RIPEMD160($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func hash160(_ data: Data) -> Data {
        return ripemd160(sha256(data))
    }
    
    static func base58Encode(_ data: Data) -> String {
        let alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
        var bytes = [UInt8](data)
        var zerosCount = 0
        
        for byte in bytes {
            if byte != 0 { break }
            zerosCount += 1
        }
        
        var encoded = ""
        var carry: Int
        
        for byte in bytes where byte != 0 || encoded.count > 0 {
            carry = Int(byte)
            for i in 0..<encoded.count {
                let index = encoded.index(encoded.startIndex, offsetBy: i)
                let char = encoded[index]
                let value = alphabet.firstIndex(of: char)!.utf16Offset(in: alphabet)
                carry += value * 256
                let newChar = alphabet[alphabet.index(alphabet.startIndex, offsetBy: carry % 58)]
                encoded.replaceSubrange(index...index, with: String(newChar))
                carry /= 58
            }
            
            while carry > 0 {
                let newChar = alphabet[alphabet.index(alphabet.startIndex, offsetBy: carry % 58)]
                encoded.append(newChar)
                carry /= 58
            }
        }
        
        let prefix = String(repeating: alphabet.first!, count: zerosCount)
        return prefix + String(encoded.reversed())
    }
    
    static func generateBitcoinAddress(from publicKey: Data) -> String {
        let pubKeyHash = hash160(publicKey)
        var addressBytes = Data([0x00]) + pubKeyHash
        let checksum = sha256(sha256(addressBytes)).prefix(4)
        addressBytes.append(checksum)
        return base58Encode(addressBytes)
    }
}

// MARK: - Keychain Manager

class KeychainManager {
    static let shared = KeychainManager()
    
    private let service = "com.cryptowallet.keys"
    
    func savePrivateKey(_ key: Data, for address: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address,
            kSecValueData as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func loadPrivateKey(for address: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecSuccess, let data = result as? Data {
            return data
        }
        return nil
    }
    
    func deletePrivateKey(for address: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess
    }
}

