    init(address: String, publicKey: String) {
        self.address = address
        self.publicKey = publicKey
        self.balance = 0.0
        self.createdAt = Date()
    }
}

// MARK: - Transaction Model

struct Transaction: Codable {
    let txid: String
    let from: String
    let to: String
    let amount: Double
    let fee: Double
    let timestamp: Date
    let signature: String
    var confirmed: Bool
    
    init(from: String, to: String, amount: Double, fee: Double, signature: String) {
        self.txid = UUID().uuidString
        self.from = from
        self.to = to
        self.amount = amount
        self.fee = fee
        self.timestamp = Date()
        self.signature = signature
        self.confirmed = false
    }
}

// MARK: - Wallet Manager

class WalletManager {
    static let shared = WalletManager()
    private var wallets: [Wallet] = []
    
    private let walletsKey = "wallets"
    
    init() {
        loadWallets()
    }
    
    func createWallet() -> Wallet {
        let privateKey = CryptoUtils.generatePrivateKey()
        let publicKey = CryptoUtils.derivePublicKey(from: privateKey)
        let address = CryptoUtils.generateBitcoinAddress(from: publicKey)
        
        let wallet = Wallet(address: address, publicKey: publicKey.hexString)
        
        _ = KeychainManager.shared.savePrivateKey(privateKey, for: address)
        
        wallets.append(wallet)
        saveWallets()
        
        return wallet
    }
    
    func getAllWallets() -> [Wallet] {
        return wallets
    }
    
    func getWallet(by address: String) -> Wallet? {
        return wallets.first { $0.address == address }
    }
    
    func updateBalance(for address: String, balance: Double) {
        if let index = wallets.firstIndex(where: { $0.address == address }) {
            wallets[index].balance = balance
            saveWallets()
        }
    }
    
    func deleteWallet(address: String) {
        wallets.removeAll { $0.address == address }
        _ = KeychainManager.shared.deletePrivateKey(for: address)
        saveWallets()
    }
    
    private func saveWallets() {
        if let encoded = try? JSONEncoder().encode(wallets) {
            UserDefaults.standard.set(encoded, forKey: walletsKey)
        }
    }
    
    private func loadWallets() {
        if let data = UserDefaults.standard.data(forKey: walletsKey),
           let decoded = try? JSONDecoder().decode([Wallet].self, from: data) {
            wallets = decoded
        }
    }
}

// MARK: - Transaction Signer

class TransactionSigner {
    static func signTransaction(from: String, to: String, amount: Double, fee: Double) -> Transaction? {
        guard let privateKeyData = KeychainManager.shared.loadPrivateKey(for: from) else {
            return nil
        }
        
        let message = "\(from)\(to)\(amount)\(fee)\(Date().timeIntervalSince1970)"
        let messageData = message.data(using: .utf8)!
        let messageHash = CryptoUtils.sha256(messageData)
        
        let signature = signData(messageHash, with: privateKeyData)
        
        return Transaction(from: from, to: to, amount: amount, fee: fee, signature: signature.hexString)
    }
    
    private static func signData(_ data: Data, with privateKey: Data) -> Data {
        var ctx = secp256k1_context_create(UInt32(SECP256K1_CONTEXT_SIGN))
        defer { secp256k1_context_destroy(ctx) }
        
        var signature = secp256k1_ecdsa_signature()
        let key = privateKey.withUnsafeBytes { Array($0) }
        let hash = data.withUnsafeBytes { Array($0) }
        
        _ = secp256k1_ecdsa_sign(ctx, &signature, hash, key, nil, nil)
        
        var output = [UInt8](repeating: 0, count: 64)
        secp256k1_ecdsa_signature_serialize_compact(ctx, &output, &signature)
        
        return Data(output)
    }
}

