class WalletListViewController: UIViewController {
    
    private let tableView = UITableView()
    private var wallets: [Wallet] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        title = "My Wallets"
        view.backgroundColor = .systemBackground
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .add, target: self, action: #selector(createWallet))
        
        setupTableView()
        loadWallets()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        loadWallets()
    }
    
    private func setupTableView() {
        tableView.frame = view.bounds
        tableView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(WalletCell.self, forCellReuseIdentifier: "WalletCell")
        view.addSubview(tableView)
    }
    
    private func loadWallets() {
        wallets = WalletManager.shared.getAllWallets()
        
        for wallet in wallets {
            BlockchainAPI.shared.getBalance(for: wallet.address) { [weak self] balance in
                if let balance = balance {
                    WalletManager.shared.updateBalance(for: wallet.address, balance: balance)
                    self?.wallets = WalletManager.shared.getAllWallets()
                    self?.tableView.reloadData()
                }
            }
        }
        
        tableView.reloadData()
    }
    
    @objc private func createWallet() {
        let alert = UIAlertController(title: "Create Wallet", message: "Are you sure you want to create a new wallet?", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Create", style: .default) { [weak self] _ in
            let wallet = WalletManager.shared.createWallet()
            self?.wallets = WalletManager.shared.getAllWallets()
            self?.tableView.reloadData()
            
            let successAlert = UIAlertController(title: "Success", message: "Wallet created!\nAddress: \(wallet.address)", preferredStyle: .alert)
            successAlert.addAction(UIAlertAction(title: "OK", style: .default))
            self?.present(successAlert, animated: true)
        })
        present(alert, animated: true)
    }
}

extension WalletListViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return wallets.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "WalletCell", for: indexPath) as! WalletCell
        cell.configure(with: wallets[indexPath.row])
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let wallet = wallets[indexPath.row]
        let detailVC = WalletDetailViewController(wallet: wallet)
        navigationController?.pushViewController(detailVC, animated: true)
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 80
    }
    
    func tableView(_ tableView: UITableView, commit editingStyle: UITableViewCell.EditingStyle, forRowAt indexPath: IndexPath) {
        if editingStyle == .delete {
            let wallet = wallets[indexPath.row]
            WalletManager.shared.deleteWallet(address: wallet.address)
            wallets.remove(at: indexPath.row)
            tableView.deleteRows(at: [indexPath], with: .fade)
        }
    }
}

