            amountTextField.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            amountTextField.heightAnchor.constraint(equalToConstant: 44),
            
            feeLabel.topAnchor.constraint(equalTo: amountTextField.bottomAnchor, constant: 24),
            feeLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            feeLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            
            feeTextField.topAnchor.constraint(equalTo: feeLabel.bottomAnchor, constant: 8),
            feeTextField.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            feeTextField.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            feeTextField.heightAnchor.constraint(equalToConstant: 44),
            
            balanceLabel.topAnchor.constraint(equalTo: feeTextField.bottomAnchor, constant: 16),
            balanceLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            
            sendButton.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 40),
            sendButton.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            sendButton.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            sendButton.heightAnchor.constraint(equalToConstant: 50),
            sendButton.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -32)
        ])
    }
    
    @objc private func sendTransaction() {
        guard let recipient = recipientTextField.text, !recipient.isEmpty else {
            showAlert(title: "Error", message: "Please enter recipient address")
            return
        }
        
        guard let amountText = amountTextField.text, let amount = Double(amountText), amount > 0 else {
            showAlert(title: "Error", message: "Please enter valid amount")
            return
        }
        
        guard let feeText = feeTextField.text, let fee = Double(feeText), fee > 0 else {
            showAlert(title: "Error", message: "Please enter valid fee")
            return
        }
        
        guard amount + fee <= wallet.balance else {
            showAlert(title: "Error", message: "Insufficient balance")
            return
        }
        
        guard let transaction = TransactionSigner.signTransaction(from: wallet.address, to: recipient, amount: amount, fee: fee) else {
            showAlert(title: "Error", message: "Failed to sign transaction")
            return
        }
        
        let loadingAlert = UIAlertController(title: "Sending", message: "Broadcasting transaction...", preferredStyle: .alert)
        present(loadingAlert, animated: true)
        
        BlockchainAPI.shared.broadcastTransaction(transaction) { [weak self] success in
            loadingAlert.dismiss(animated: true) {
                if success {
                    self?.showAlert(title: "Success", message: "Transaction sent successfully!\n\nTXID: \(transaction.txid)") {
                        self?.navigationController?.popViewController(animated: true)
                    }
                } else {
                    self?.showAlert(title: "Error", message: "Failed to broadcast transaction")
                }
            }
        }
    }
    
    private func showAlert(title: String, message: String, completion: (() -> Void)? = nil) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completion?()
        })
        present(alert, animated: true)
    }
}

